/// <summary>
/// Runs the optional <see cref="RelayConfig.BuildCommand"/> in a shell with
/// the same sandbox environment as the test command, but WITHOUT the nono
/// sandbox wrapper (so it is testable via RecordingTestRunner and avoids
/// nono session-directory issues in restricted environments). Uses
/// <see cref="RelayConfig.BuildTimeoutMilliseconds"/> as the hard cap (0 = no cap).
/// Returns a <see cref="TestRunResult"/> that surfaces exit code, output, and
/// timeout for the caller to decide whether to proceed to the test phase.
/// </summary>
private async Task<TestRunResult> RunBuildCommandAsync(
    string rootPath, RelayConfig config, CancellationToken ct)
{
    var env = SwivalSubagentRunner.BuildSandboxEnvironment(config);
    var args = new List<string> { "-c", config.BuildCommand! };

    var timeout = config.BuildTimeoutMilliseconds > 0
        ? TimeSpan.FromMilliseconds(config.BuildTimeoutMilliseconds)
        : System.Threading.Timeout.InfiniteTimeSpan;

    var sw = Stopwatch.StartNew();
    var (exitCode, output, timedOut) = await ProcessCapture.RunAsync(
        "/bin/sh", args, rootPath, timeout, ct, environment: env);
    return new TestRunResult(exitCode, output, timedOut, sw.Elapsed);
}

